{% extends "base.html" %}

{% block title %}Inbox -- Todo List{% endblock %}

{% block nav %}
{% include "gtd_nav.html" %}
{% endblock %}

{% block content %}
<div class="inbox">
    <h1>Inbox</h1>

    <form
        method="post"
        action="/inbox"
        class="inbox-capture"
        hx-post="/inbox"
        hx-target="#inbox-list"
        hx-swap="beforeend"
        hx-on::after-request="if(event.detail.successful) this.reset(); this.querySelector('#inbox-title').focus();"
    >
        <label for="inbox-title">Capture</label>
        <input
            type="text"
            id="inbox-title"
            name="title"
            placeholder="What's on your mind?"
            maxlength="300"
            autocomplete="off"
            class="inbox-capture__input"
        >
        <button type="submit" class="inbox-capture__submit">Capture</button>
    </form>

    {% if items.is_empty() %}
    <div class="inbox__empty-state" id="inbox-empty-state">
        <p>Inbox zero -- nothing to process. <a href="#inbox-title">Capture something new</a> or start your <a href="/review">weekly review</a>.</p>
    </div>
    {% endif %}
    <ul class="inbox__list" role="list" id="inbox-list"{% if items.is_empty() %} hidden{% endif %}>
        {% for item in items %}
        {% include "inbox_item.html" %}
        {% endfor %}
    </ul>
</div>
{% endblock %}

{% block scripts %}
<script>
// Hide empty state and show list when items are added via HTMX
document.getElementById('inbox-list').addEventListener('htmx:afterSwap', function() {
    var list = document.getElementById('inbox-list');
    var emptyState = document.getElementById('inbox-empty-state');
    if (list && list.children.length > 0) {
        list.hidden = false;
        if (emptyState) emptyState.hidden = true;
    }
});
// Show empty state when list becomes empty after HTMX delete
document.body.addEventListener('htmx:afterSettle', function() {
    var list = document.getElementById('inbox-list');
    var emptyState = document.getElementById('inbox-empty-state');
    if (list && list.children.length === 0 && emptyState) {
        list.hidden = true;
        emptyState.hidden = false;
    }
});
</script>
{% endblock %}

use chrono::{DateTime, Utc};
use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::{InboxItem, InboxItemId, TodoTitle, UserId};

struct InboxRecord {
    id: Uuid,
    user_id: Uuid,
    title: String,
    created_at: DateTime<Utc>,
}

impl InboxRecord {
    fn into_domain(self) -> InboxItem {
        let id = InboxItemId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");

        InboxItem::from_parts(id, user_id, title, self.created_at)
    }
}

pub async fn insert_inbox_item(pool: &PgPool, item: &InboxItem) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"INSERT INTO inbox_items (id, user_id, title, created_at)
           VALUES ($1, $2, $3, $4 :: timestamptz)"#,
        item.id().as_uuid(),
        item.user_id().as_uuid(),
        item.title().as_str(),
        item.created_at() as &DateTime<Utc>,
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_inbox_items_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<InboxItem>, sqlx::Error> {
    let records = sqlx::query_as!(
        InboxRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>"
           FROM inbox_items WHERE user_id = $1 ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records
        .into_iter()
        .map(|r: InboxRecord| r.into_domain())
        .collect())
}

pub async fn count_inbox_items(pool: &PgPool, user_id: &UserId) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM inbox_items WHERE user_id = $1"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

pub async fn delete_inbox_item(pool: &PgPool, item_id: &InboxItemId) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM inbox_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_inbox_item_by_id(
    pool: &PgPool,
    item_id: &InboxItemId,
) -> Result<Option<InboxItem>, sqlx::Error> {
    let record: Option<InboxRecord> = sqlx::query_as!(
        InboxRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>"
           FROM inbox_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .fetch_optional(pool)
    .await?;

    Ok(record.map(|r: InboxRecord| r.into_domain()))
}

use chrono::{DateTime, Utc};
use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::{ContextId, NextAction, NextActionId, TodoTitle, UserId};

struct NextActionRecord {
    id: Uuid,
    user_id: Uuid,
    context_id: Uuid,
    title: String,
    created_at: DateTime<Utc>,
    completed_at: Option<DateTime<Utc>>,
}

impl NextActionRecord {
    fn into_domain(self) -> NextAction {
        let id = NextActionId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let context_id = ContextId::from_uuid(self.context_id);
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");

        NextAction::from_parts(
            id,
            user_id,
            context_id,
            title,
            self.created_at,
            self.completed_at,
        )
    }
